const cities = [
  'Houston', 'San Antonio', 'Dallas', 'Austin', 'Fort Worth',
  'El Paso', 'Arlington', 'Corpus Christi', 'Plano', 'Lubbock',
  'Laredo', 'Irving', 'Amarillo', 'Grand Prairie', 'Brownsville',
  'McKinney', 'Frisco', 'Pasadena', 'Killeen', 'McAllen'
];

return cities.map(city => ({
  json: {
    city,
    query: `auto repair shop in ${city}, Texas`,
    state: 'TX'
  }
}));

const resp = $input.first().json;
const cityData = $('Loop Over Cities').first().json;
const results = resp.results || [];

const leads = results.map(place => {
  const name = (place.name || '').trim();
  const address = (place.formatted_address || '').trim();
  const placeId = place.place_id || null;

  return {
    business_name: name,
    address,
    place_id: placeId,
    city: cityData.city,
    state: cityData.state
  };
}).filter(l => l.place_id);

return [{
  json: {
    city: cityData.city,
    leads,
    count: leads.length,
    next_page_token: resp.next_page_token || null
  }
}];

const input = $input.first().json;
const leads = input.leads || [];

if (leads.length === 0) {
  return [{ json: { city: input.city, count: 0, place_ids: [] } }];
}

return leads.map(lead => ({ json: lead }));

const detailItems = $input.all();
const expandItems = $('Code - Expand Leads').all();

function extractDomain(url) {
  if (!url || typeof url !== 'string') return null;
  try {
    let d = url.trim().toLowerCase();
    d = d.replace(/^https?:\/\//, '').replace(/^www\./, '');
    d = d.split('/')[0].split('?')[0].split('#')[0];
    d = d.replace(/:\d+$/, '');
    return (d && d.includes('.')) ? d : null;
  } catch (e) { return null; }
}

const rows = [];

for (let i = 0; i < detailItems.length; i++) {
  const detail = detailItems[i].json?.result || detailItems[i].json || {};
  const base = expandItems[i]?.json || {};
  const website = (detail.website || '').trim() || null;
  const domain = extractDomain(website);
  const phone = (detail.formatted_phone_number || '').trim() || null;
  const bizStatus = (detail.business_status || '').toUpperCase();
  if (bizStatus === 'CLOSED_PERMANENTLY') continue;

  rows.push({
    business_name: base.business_name || detail.name || '',
    website, domain, phone,
    address: detail.formatted_address || base.address || '',
    city: base.city || '',
    state: base.state || 'TX',
    place_id: base.place_id || ''
  });
}

return [{ json: { rows, count: rows.length } }];

const apiResp = $input.first().json;
const city = $('Loop Over Cities').first().json.city;

return [{
  json: {
    city,
    scraped: apiResp.submitted || 0,
    inserted: apiResp.inserted || 0,
    skipped_dupes: apiResp.skipped || 0
  }
}];
